+function drawRoom(ctx: CanvasRenderingContext2D, x: number, y: number, scale: number, roomType: string) {
+  // Draw floor with thematic tile pattern
+  drawTiledFloor(ctx, x, y, 80, 64, scale, roomType);
+
+  switch(roomType) {
+    case 'throneRoom':
+      // Two pieces: Throne and Planning Table
+      drawThrone(ctx, x + 10 * scale, y + 4 * scale, scale);
+      drawPlanningTable(ctx, x + 50 * scale, y + 12 * scale, scale);
+      break;
+    case 'armory':
+      // Weapon Rack and Workbench
+      drawWeaponRack(ctx, x + 8 * scale, y + 8 * scale, scale);
+      drawWorkbench(ctx, x + 48 * scale, y + 12 * scale, scale);
+      break;
+    case 'alchemyLab':
+      // Potion Shelf and Scribe Desk
+      drawPotionShelf(ctx, x + 12 * scale, y + 6 * scale, scale);
+      drawScribeDesk(ctx, x + 52 * scale, y + 14 * scale, scale);
+      break;
+  }
+}
+
+// ─── Tile Pattern Drawing Helpers ─────────────────────────────────────────────
+
+function drawTiledFloor(ctx: CanvasRenderingContext2D, x: number, y: number, width: number, height: number, scale: number, roomType: string) {
+  const tileSize = 16;
+  const cols = Math.ceil(width / tileSize);
+  const rows = Math.ceil(height / tileSize);
+
+  // Select tile drawer based on roomType thematic floor
+  let tileDrawer: (ctx: CanvasRenderingContext2D, x: number, y: number, s: number, variant: number) => void;
+  switch(roomType) {
+    case 'throneRoom':
+      tileDrawer = drawStoneTile;
+      break;
+    case 'armory':
+      tileDrawer = drawWoodTile;
+      break;
+    case 'alchemyLab':
+      tileDrawer = drawCarpetTile;
+      break;
+    default:
+      tileDrawer = drawCobblestoneTile;
+      break;
+  }
+
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      // Variant can be used to add subtle pattern variation
+      const variant = (row + col) % 4;
+      tileDrawer(ctx, x + col * tileSize * scale, y + row * tileSize * scale, scale, variant);
+    }
+  }
+}
+
+// ─── Tile Pattern Implementations ──────────────────────────────────────────────
+
+// Stone tile: gray blocks with mortar lines
+function drawStoneTile(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, variant: number) {
+  const size = 16 * s;
+  // Base stone color
+  ctx.fillStyle = '#7a7a7a';
+  ctx.fillRect(x, y, size, size);
+
+  // Mortar lines: lighter gray lines forming blocks
+  ctx.strokeStyle = '#b0b0b0';
+  ctx.lineWidth = s * 1.5;
+  ctx.beginPath();
+  // Vertical mortar lines
+  ctx.moveTo(x + size * 0.33, y);
+  ctx.lineTo(x + size * 0.33, y + size);
+  ctx.moveTo(x + size * 0.66, y);
+  ctx.lineTo(x + size * 0.66, y + size);
+  // Horizontal mortar lines
+  ctx.moveTo(x, y + size * 0.5);
+  ctx.lineTo(x + size, y + size * 0.5);
+  ctx.stroke();
+
+  // Add subtle shading variation by variant
+  if (variant === 1) {
+    ctx.fillStyle = 'rgba(0,0,0,0.1)';
+    ctx.fillRect(x + size * 0.33, y, size * 0.33, size * 0.5);
+  } else if (variant === 2) {
+    ctx.fillStyle = 'rgba(255,255,255,0.1)';
+    ctx.fillRect(x, y + size * 0.5, size * 0.33, size * 0.5);
+  }
+}
+
+// Wood tile: horizontal planks with grain
+function drawWoodTile(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, variant: number) {
+  const size = 16 * s;
+  // Base wood plank color
+  ctx.fillStyle = '#a9744f';
+  ctx.fillRect(x, y, size, size);
+
+  // Draw horizontal plank lines
+  ctx.strokeStyle = '#6b4a2e';
+  ctx.lineWidth = s * 1.2;
+  for (let i = 1; i <= 3; i++) {
+    const yLine = y + (size / 4) * i;
+    ctx.beginPath();
+    ctx.moveTo(x, yLine);
+    ctx.lineTo(x + size, yLine);
+    ctx.stroke();
+  }
+
+  // Draw grain lines (curved thin lines)
+  ctx.strokeStyle = '#8b5e3c';
+  ctx.lineWidth = s * 0.5;
+  ctx.beginPath();
+  const grainY = y + size * 0.2;
+  ctx.moveTo(x + size * 0.1, grainY);
+  ctx.bezierCurveTo(x + size * 0.3, grainY + size * 0.05, x + size * 0.6, grainY - size * 0.05, x + size * 0.9, grainY + size * 0.05);
+  ctx.stroke();
+
+  if (variant === 3) {
+    // Add a knot circle
+    ctx.fillStyle = '#6b4a2e';
+    ctx.beginPath();
+    ctx.ellipse(x + size * 0.7, y + size * 0.6, size * 0.8 * 0.1, size * 0.8 * 0.07, 0, 0, Math.PI * 2);
+    ctx.fill();
+  }
+}
+
+// Carpet tile: red with border pattern
+function drawCarpetTile(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, variant: number) {
+  const size = 16 * s;
+  // Base carpet red
+  ctx.fillStyle = '#b22222';
+  ctx.fillRect(x, y, size, size);
+
+  // Draw border pattern
+  ctx.strokeStyle = '#7f0000';
+  ctx.lineWidth = s * 1.5;
+  ctx.strokeRect(x + s * 1, y + s * 1, size - s * 2, size - s * 2);
+
+  // Inner diamond pattern
+  ctx.strokeStyle = '#8b0000';
+  ctx.lineWidth = s * 1;
+  ctx.beginPath();
+  ctx.moveTo(x + size / 2, y + s * 2);
+  ctx.lineTo(x + size - s * 2, y + size / 2);
+  ctx.lineTo(x + size / 2, y + size - s * 2);
+  ctx.lineTo(x + s * 2, y + size / 2);
+  ctx.closePath();
+  ctx.stroke();
+
+  // Variant subtle dot pattern
+  if (variant === 2) {
+    ctx.fillStyle = '#7f0000';
+    ctx.beginPath();
+    ctx.arc(x + size * 0.3, y + size * 0.3, s * 1.5, 0, Math.PI * 2);
+    ctx.fill();
+    ctx.beginPath();
+    ctx.arc(x + size * 0.7, y + size * 0.7, s * 1.5, 0, Math.PI * 2);
+    ctx.fill();
+  }
+}
+
+// Cobblestone tile: irregular circles
+function drawCobblestoneTile(ctx: CanvasRenderingContext2D, x: number, y: number, s: number, variant: number) {
+  const size = 16 * s;
+  // Base dirt color
+  ctx.fillStyle = '#6b5a4f';
+  ctx.fillRect(x, y, size, size);
+
+  // Draw cobblestones as irregular circles
+  const stones = [
+    { cx: 4, cy: 6, rx: 5, ry: 4 },
+    { cx: 12, cy: 10, rx: 4, ry: 5 },
+    { cx: 8, cy: 14, rx: 6, ry: 3 },
+  ];
+
+  ctx.fillStyle = '#8c7b6a';
+  ctx.strokeStyle = '#4a3a2a';
+  ctx.lineWidth = s * 0.8;
+  stones.forEach(({ cx, cy, rx, ry }, i) => {
+    // Slight offset by variant for subtle variation
+    const offsetX = ((variant + i) % 3) - 1;
+    const offsetY = ((variant * 2 + i) % 3) - 1;
+    ctx.beginPath();
+    ctx.ellipse(
+      x + (cx + offsetX) * s,
+      y + (cy + offsetY) * s,
+      rx * s,
+      ry * s,
+      Math.PI / 8 * i,
+      0,
+      Math.PI * 2
+    );
+    ctx.fill();
+    ctx.stroke();
+  });
+}
